const totpsTable = snakeCase.table(
  'totps',
  {
    id: uuid().primaryKey().$defaultFn(generateId),
    userId: uuid()
      .notNull()
      .references(() => usersTable.id, { onDelete: 'cascade' }),
    secret: varchar({ length: maxLength.field }).notNull(),
    createdAt: timestampColumns.createdAt,
  },
  (table) => [index('totps_user_id_idx').on(table.userId)],
);

const updateMe = async (ctx: AuthContext, { values }: UpdateMeOpts) => {
  const { db, userId } = ctx.var;
  const { userFlags, ...rest } = values;

  const updateData = {
    ...rest,
    ...(userFlags && {
      userFlags: sql`${usersTable.userFlags} || ${JSON.stringify(userFlags)}::jsonb`,
    }),
  };

  return db.update(usersTable).set(updateData).where(eq(usersTable.id, userId));
};

const idsWithStxBodySchema = (maxItems = 50) =>
  z.object({
    ids: z
      .array(z.string())
      .min(1, t('error:invalid_min_items', { min: 'one', name: 'ID' }))
      .max(maxItems, t('error:invalid_max_items', { max: maxItems, name: 'ID' })),
    stx: z
      .object({
        mutationId: z.string(),
        sourceId: z.string(),
      })
      .optional(),
  });

const streamCatchupBodySchema = z.object({
  cursor: z.string().optional().openapi({
    description: 'Last activity cursor received by the client (LSN-based). Omit on first sync.',
    example: '0-16B3748',
  }),
  seqs: z
    .record(z.string(), z.number().int())
    .optional()
    .openapi({
      description: 'Client-side sequence numbers per scope: { "organizationId:s:page": 42 }',
      example: { 'abc123:s:page': 10 },
    }),
});

baseApp.get('/health', async (c) => {
  const depth = c.req.query('depth') ?? 'shallow';
  const version = env.RELEASE_SHA;
  c.header('X-App-Version', version);

  if (depth === 'shallow') {
    c.header('Cache-Control', 'public, max-age=5');
    return c.body(null, 204);
  }

  const { response, httpStatus } = await getHealthResponse();
  if (httpStatus >= 200 && httpStatus < 300) {
    c.header('Cache-Control', 'public, max-age=10, stale-while-revalidate=5');
  }
  return c.json({ ...response, version }, httpStatus as 200);
});

const toSubnet = (ip: string): string | null => {
  if (!ip) return null;
  // Strip IPv4-mapped IPv6 prefix so 192.168.0.1 and ::ffff:192.168.0.1 collapse.
  const normalized = ip.startsWith('::ffff:') ? ip.slice(7) : ip;
  if (isIPv4(normalized)) {
    const parts = normalized.split('.');
    return `${parts[0]}.${parts[1]}.${parts[2]}.0/24`;
  }
  if (isIPv6(normalized)) {
    // Expand to full form, take first 3 groups, zero the rest.
    const groups = expandIPv6(normalized);
    if (!groups) return null;
    return `${groups[0]}:${groups[1]}:${groups[2]}::/48`;
  }
  return null;
};

const createResult = async (res: Response): Promise<CloudFrontResult> => {
  const isBase64Encoded = isContentTypeBinary(res.headers.get('content-type') || '')
  const body = isBase64Encoded ? encodeBase64(await res.arrayBuffer()) : await res.text()

  return {
    status: res.status.toString(),
    headers: convertHeaders(res.headers),
    body,
    ...(isBase64Encoded && { bodyEncoding: 'base64' }),
  }
}

const getB2BClient = (c: Context) => {
  const stytchEnv = env<StytchEnv>(c)
  b2bClients[stytchEnv.STYTCH_PROJECT_ID] =
    b2bClients[stytchEnv.STYTCH_PROJECT_ID] ||
    new B2BClient({
      project_id: stytchEnv.STYTCH_PROJECT_ID,
      secret: stytchEnv.STYTCH_PROJECT_SECRET,
      custom_base_url: stytchEnv.STYTCH_DOMAIN,
    })
  return b2bClients[stytchEnv.STYTCH_PROJECT_ID]
}

if (info.files) {
	return {
		rootName: torrentName,
		files: info.files.map((file) => {
			const pathParts = file.path || []
			const internalPath = pathParts.map((p) => p.toString()).join('/')
			return {
				name: pathParts.length > 0 ? pathParts[pathParts.length - 1].toString() : '',
				path: torrentName ? `${torrentName}/${internalPath}` : internalPath,
				size: Number(file.length),
			}
		}),
	}
}

router.get("/logs", (c) => {
  const ruleId = c.req.query("ruleId");
  const orderId = c.req.query("orderId");
  const accountId = c.req.query("accountId");
  const limit = parseInt(c.req.query("limit") || "50");
  const offset = parseInt(c.req.query("offset") || "0");

  const result = getDeliveryLogs({
    ruleId: ruleId ? parseInt(ruleId) : undefined,
    orderId: orderId || undefined,
    accountId: accountId || undefined,
    limit,
    offset,
  });
  return c.json(result);
});
